# TypeScript 基础笔记

## 1. 什么是 TypeScript

TypeScript 是 JavaScript 的超集，添加了静态类型系统和其他高级特性，由 Microsoft 开发和维护。

### 主要优势

- 提供静态类型检查，减少运行时错误

- 增强了代码提示和自动补全

- 使代码更易于维护和重构

- 支持最新的 ECMAScript 特性

## 2. 基本类型

```typescript
// 基本类型
let isDone: boolean = false;
let decimal: number = 6;
let color: string = "blue";
let list: number[] = [1, 2, 3];
let tuple: [string, number] = ["hello", 10];

// 枚举
enum Color {Red, Green, Blue}
let c: Color = Color.Green;

// Any 类型
let notSure: any = 4;
notSure = "maybe a string";

// Void 类型
function warnUser(): void {
  console.log("This is a warning message");
}

// Null 和 Undefined
let u: undefined = undefined;
let n: null = null;

// Never 类型
function error(message: string): never {
  throw new Error(message);
}

```

## 3. 接口

```typescript
// 定义接口
interface User {
  name: string;
  id: number;
  email?: string; // 可选属性
  readonly createdAt: Date; // 只读属性
}

// 使用接口
const user: User = {
  name: "张三",
  id: 1,
  createdAt: new Date()
};

// 函数接口
interface SearchFunc {
  (source: string, subString: string): boolean;
}

let mySearch: SearchFunc = function(src, sub) {
  return src.search(sub) > -1;
};

```

## 4. 类

```typescript
class Animal {
  // 属性
  private name: string;

  // 构造函数
  constructor(name: string) {
    this.name = name;
  }

  // 方法
  public move(distance: number = 0): void {
    console.log(`${this.name} moved ${distance}m.`);
  }

  // 获取器
  get theName(): string {
    return this.name;
  }
}

// 继承
class Dog extends Animal {
  constructor(name: string) {
    super(name);
  }

  bark(): void {
    console.log('Woof! Woof!');
  }

  move(distance: number = 5): void {
    console.log('Running...');
    super.move(distance);
  }
}

```

## 5. 函数

```typescript
// 函数类型
function add(x: number, y: number): number {
  return x + y;
}

// 可选参数
function buildName(firstName: string, lastName?: string): string {
  if (lastName) {
    return firstName + " " + lastName;
  }
  return firstName;
}

// 默认参数
function greet(name: string, greeting: string = "Hello"): string {
  return `${greeting}, ${name}!`;
}

// 剩余参数
function sum(...numbers: number[]): number {
  return numbers.reduce((total, n) => total + n, 0);
}

// 函数重载
function padding(all: number): {top: number, right: number, bottom: number, left: number};
function padding(topAndBottom: number, leftAndRight: number): {top: number, right: number, bottom: number, left: number};
function padding(top: number, right: number, bottom: number, left: number): {top: number, right: number, bottom: number, left: number};
function padding(a: number, b?: number, c?: number, d?: number) {
  if (b === undefined && c === undefined && d === undefined) {
    b = c = d = a;
  } else if (c === undefined && d === undefined) {
    c = a;
    d = b;
  }
  return {
    top: a,
    right: b,
    bottom: c,
    left: d
  };
}

```

## 6. 泛型

```typescript
// 泛型函数
function identity<T>(arg: T): T {
  return arg;
}

// 使用泛型函数
let output = identity<string>("myString");
let output2 = identity("myString"); // 类型推断

// 泛型接口
interface GenericIdentityFn<T> {
  (arg: T): T;
}

// 泛型类
class GenericNumber<T> {
  zeroValue: T;
  add: (x: T, y: T) => T;
}

// 泛型约束
interface Lengthwise {
  length: number;
}

function loggingIdentity<T extends Lengthwise>(arg: T): T {
  console.log(arg.length);  // 现在我们知道它有一个length属性，所以不会报错
  return arg;
}

```

## 7. 高级类型

```typescript
// 联合类型
function padLeft(value: string, padding: string | number) {
  // ...
}

// 类型别名
type Name = string;
type NameResolver = () => string;
type NameOrResolver = Name | NameResolver;

// 字符串字面量类型
type Easing = "ease-in" | "ease-out" | "ease-in-out";

// 数字字面量类型
type Dice = 1 | 2 | 3 | 4 | 5 | 6;

// 交叉类型
interface ErrorHandling {
  success: boolean;
  error?: { message: string };
}

interface ArtworksData {
  artworks: { title: string }[];
}

type ArtworksResponse = ArtworksData & ErrorHandling;

// 条件类型
type TypeName<T> = 
  T extends string ? "string" :
  T extends number ? "number" :
  T extends boolean ? "boolean" :
  T extends undefined ? "undefined" :
  T extends Function ? "function" :
  "object";

```

## 8. 模块与命名空间

```typescript
// 导出
export interface StringValidator {
  isAcceptable(s: string): boolean;
}

export const numberRegexp = /^[0-9]+$/;

// 导入
import { StringValidator } from "./StringValidator";
import * as validator from "./validator";

// 命名空间
namespace Validation {
  export interface StringValidator {
    isAcceptable(s: string): boolean;
  }
}

```

## 9. 装饰器

```typescript
// 类装饰器
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

@sealed
class Greeter {
  greeting: string;
  constructor(message: string) {
    this.greeting = message;
  }
  greet() {
    return "Hello, " + this.greeting;
  }
}

// 方法装饰器
function enumerable(value: boolean) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    descriptor.enumerable = value;
  };
}

// 属性装饰器
function format(formatString: string) {
  return function (target: any, propertyKey: string) {
    let value = target[propertyKey];

    const getter = function() {
      return `${formatString} ${value}`;
    };

    const setter = function(newVal: string) {
      value = newVal;
    };

    Object.defineProperty(target, propertyKey, {
      get: getter,
      set: setter,
      enumerable: true,
      configurable: true
    });
  };
}

```

## 10. 实用工具类型

```typescript
// Partial - 将所有属性设为可选
interface Todo {
  title: string;
  description: string;
}

function updateTodo(todo: Todo, fieldsToUpdate: Partial<Todo>) {
  return { ...todo, ...fieldsToUpdate };
}

// Required - 将所有属性设为必需
type RequiredTodo = Required<Todo>;

// Readonly - 将所有属性设为只读
type ReadonlyTodo = Readonly<Todo>;

// Record - 构造一个类型，其属性名的类型为K，属性值的类型为T
type PageInfo = {
  title: string;
};

type Page = "home" | "about" | "contact";

const nav: Record<Page, PageInfo> = {
  home: { title: "Home" },
  about: { title: "About" },
  contact: { title: "Contact" },
};

// Pick - 从类型T中选择一组属性K
type TodoPreview = Pick<Todo, "title">;

// Omit - 从类型T中删除一组属性K
type TodoInfo = Omit<Todo, "description">;

```

## 11. TypeScript 配置

典型的 tsconfig.json 配置文件：

```json
{
  "compilerOptions": {
    "target": "es2020",
    "module": "commonjs",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "outDir": "./dist",
    "rootDir": "./src",
    "declaration": true,
    "sourceMap": true
  },
  "include": ["src/**/*"],
  "exclude": ["node_modules", "**/*.spec.ts"]
}

```

## 12. 资源链接

- [TypeScript 官方文档](https://www.typescriptlang.org/docs/)

- [TypeScript GitHub 仓库](https://github.com/microsoft/TypeScript)

- [TypeScript Playground](https://www.typescriptlang.org/play) - 在线尝试 TypeScript

```javascript
class MyPromiseV2 {
  constructor(executor) {
    this.state = 'pending';
    this.result = undefined;
    this.fulfilledQueue = [];
    this.rejectedQueue = [];

    const resolve = (value) => {
      if (this.state !== 'pending') return;
      this.state = 'fulfilled';
      this.result = value;
      this.fulfilledQueue.forEach(cb => cb()); // 注意这里不再传 result
    };

    const reject = (reason) => {
      if (this.state !== 'pending') return;
      this.state = 'rejected';
      this.result = reason;
      this.rejectedQueue.forEach(cb => cb());
    };

    try {
      executor(resolve, reject);
    } catch (error) {
      reject(error);
    }
  }

  then(onFulfilled, onRejected) {
    // 关键升级：返回一个全新的 Promise
    const newPromise = new MyPromiseV2((resolve, reject) => {
      const scheduleFulfilled = () => {
        // 使用 setTimeout 模拟异步微任务
        setTimeout(() => {
          try {
            if (!onFulfilled) {
              // 如果没有提供 onFulfilled，则直接 resolve 上一个 promise 的结果
              resolve(this.result);
            } else {
              // 执行回调，并拿到返回值
              const x = onFulfilled(this.result);
              // resolvePromise 会处理返回值 x
              resolvePromise(newPromise, x, resolve, reject);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      const scheduleRejected = () => {
        setTimeout(() => {
          try {
            if (!onRejected) {
              reject(this.result);
            } else {
              const x = onRejected(this.result);
              resolvePromise(newPromise, x, resolve, reject);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      if (this.state === 'fulfilled') {
        scheduleFulfilled();
      } else if (this.state === 'rejected') {
        scheduleRejected();
      } else if (this.state === 'pending') {
        this.fulfilledQueue.push(scheduleFulfilled);
        this.rejectedQueue.push(scheduleRejected);
      }
    });

    return newPromise;
  }
}

/**
 * 这是一个核心辅助函数，用来处理 .then 回调函数的返回值 x
 * @param {MyPromiseV2} newPromise then 方法返回的新 Promise
 * @param {*} x onFulfilled 或 onRejected 的返回值
 * @param {Function} resolve newPromise 的 resolve 函数
 * @param {Function} reject newPromise 的 reject 函数
 */
function resolvePromise(newPromise, x, resolve, reject) {
  // 防止循环引用
  if (newPromise === x) {
    return reject(new TypeError('Chaining cycle detected for promise'));
  }

  // 如果 x 是一个 Promise，则 newPromise 的状态跟随 x 的状态
  if (x instanceof MyPromiseV2) {
    x.then(resolve, reject);
  } 
  // 如果 x 是一个普通值，则直接 resolve
  else {
    resolve(x);
  }
}
```

浏览器环境下**不允许**直接打开原生 UDP Socket，这是出于安全与稳定性的考虑。但如果你需要在浏览器中实现类似 UDP 的无连接、低延迟、可丢包的数据传输，可以借助以下几种 Web 标准接口：



## 1. 为什么不能直接用 UDP

- 浏览器沙箱模型限制：浏览器脚本运行在受限环境，不能访问底层网络栈，以免被滥用发起任意网络请求或探测局域网设备。

- HTTP/HTTPS 和 WebSocket 都基于 TCP，无法直接提供 UDP 那样的不可靠、无连接语义。



## 2. 替代方案

### 2.1 WebSocket （基于 TCP）

- 优点：简单、广泛支持，浏览器和服务器端都有成熟库。

- 缺点：基于 TCP，保证可靠有序，无法丢包或乱序，对实时性要求高的场景不够灵活。

```plain text
const ws = new WebSocket('wss://example.com/socket');
ws.onopen = () => ws.send('hello');
ws.onmessage = e => console.log(e.data);
```



### 2.2 WebRTC DataChannel （基于 UDP+SCTP）

- WebRTC 在底层使用 DTLS+UDP，然后在其上跑 SCTP，为你暴露**可靠**与**不可靠**（即“类 UDP”）两种通道。

- **可靠通道**：像 TCP 一样保证顺序与重传；

- **不可靠通道**：可以配置最大重传次数或完全不重传，支持乱序接收，适合实时音视频或游戏状态同步。

```plain text
// 省略信令过程，只示例 DataChannel 创建
const pc = new RTCPeerConnection();
const dc = pc.createDataChannel('game', {
  ordered: false,        // 不保证顺序
  maxRetransmits: 0      // 不重传
});
dc.onmessage = e => console.log('recv', e.data);
dc.send(new Uint8Array([1,2,3]));
```



### 2.3 WebTransport Datagram （基于 QUIC/UDP，实验性）

- WebTransport 是 W3C 新标准，底层使用 HTTP/3（QUIC over UDP），支持 **可靠流** 和 **不可靠 datagram**。

- 需要浏览器与服务器同时支持，目前 Chrome（部分版本）中可用。

```plain text
// 需在 HTTPS+HTTP/3 环境下，且服务器支持 WebTransport
const transport = new WebTransport('https://example.com:4433/');
await transport.ready;
const sender = await transport.createDatagramSender();
const { readable } = transport.datagrams;
const reader = readable.getReader();
sender.write(new Uint8Array([1,2,3]));      // 发 datagram
const { value } = await reader.read();      // 收 datagram
console.log(value);
```



## 3. 选择建议

- **简单双向通信** → WebSocket；

- **实时音视频、点对点数据** → WebRTC DataChannel；

- **未来高性能无连接传输** → WebTransport Datagram（注意兼容性）。



### 小结

- **浏览器端无法直接使用 UDP Socket**；

- 可通过 **WebRTC DataChannel** 或 **WebTransport Datagram** 等标准，获得类似 UDP 的不可靠、低延迟数据传输能力；

- 在兼容性或后端支持不足时，可退而使用 **WebSocket**（基于 TCP）。

## 🚀 核心新特性

### 1. Actions (异步功能增强)

React 19 引入了对在 HTML 标签中使用异步函数的内置支持，特别是在 `<form>` 中。它可以自动处理待处理状态、错误、乐观更新和顺序提交。

- **用法：** 直接将异步函数传递给 `action` 属性。

```javascript
<form action={async (formData) => {
  const error = await updateName(formData.get("name"));
  if (error) {
    showError(error);
  }
}}>
  <input name="name" />
  <button type="submit">更新</button>
</form>
```



## 🎣 新增 Hooks (Actions 相关)

### 1. `useActionState`

用于处理 Action 的状态（原名为 `useFormState`）。

```javascript
// (state, formAction, isPending) = useActionState(actionFn, initialState)
const [error, submitAction, isPending] = useActionState(
  async (previousState, formData) => {
    const error = await updateName(formData.get("name"));
    return error; // 返回的新状态
  },
  null
);
```

### 2. `useFormStatus`

在子组件中获取父级表单的提交状态，无需通过 props 传递。

```javascript
function SubmitButton() {
  const { pending, data, method, action } = useFormStatus();
  return <button disabled={pending}>{pending ? "提交中..." : "提交"}</button>;
}
```

### 3. `useOptimistic`

用于实现“乐观更新”，即在异步请求完成前，先假设成功并更新 UI。

```javascript
const [optimisticName, addOptimisticName] = useOptimistic(
  currentName,
  (state, newName) => newName // 更新逻辑
);
```



## 增强的 `use` API

`use` 是一个新的 API，可以在循环和条件语句中读取资源（如 Promise 或 Context）。

- **读取 Promise：** 结合 `Suspense` 使用。

```javascript
import { use } from "react";

function MessageComponent({ messagePromise }) {
  const content = use(messagePromise); // 自动等待 Promise 完成
  return <p>{content}</p>;
}
```

- **读取 Context：** 可以根据条件读取 Context。

```javascript
function Button() {
  const theme = use(ThemeContext); // 比 useContext 更灵活
  return <div style={{ color: theme.color }}>按钮</div>;
}
```



## 重大改进与简化

### 1. Ref 作为 Prop (不再需要 `forwardRef`)

从 React 19 开始，你可以将 `ref` 作为普通 prop 传递给函数组件，不再需要 `forwardRef` 高阶组件。

```javascript
function MyInput({ placeholder, ref }) {
  return <input placeholder={placeholder} ref={ref} />;
}

// 使用时
<MyInput ref={inputRef} />
```

### 2. 文档元数据支持

React 19 原生支持在组件中编写 `<title>`、`<meta>` 和 `<link>`，它们会被自动提升到文档的 `<head>` 中。

```javascript
function BlogPost({ post }) {
  return (
    <article>
      <title>{post.title}</title>
      <meta name="description" content={post.summary} />
      <h1>{post.title}</h1>
    </article>
  );
}
```

### 3. 样式表支持

React 19 会自动管理样式表的加载顺序和优先级。

```javascript
function MyComponent() {
  return (
    <div>
      <link rel="stylesheet" href="style.css" precedence="default" />
      <p>自动处理样式加载</p>
    </div>
  );
}
```



## 自动性能优化：React Compiler

这是 React 19 背后最大的变化。编译器会自动将你的代码转换为记忆化（Memoized）版本。

- **不再需要：** (useMemo)、(useCallback)、(React.memo)。

- **原理：** 编译器会检测数据流，只有当依赖项真正改变时，才会重新计算或渲染相关部分。公式化的理解就是 (UI = Compiler(Component))。



## 过时 API 与 迁移提醒

import { useMemo } from 'react';
import {
  Button,
  Typography,
} from 'antd';
import { useNavigate } from 'react-router-dom';

import { useBlogList, useBlogDashboard } from '@/hooks';
import type { PostFilter, BlogPost } from '@/types';
import { PostStatus } from '@/generated/graphql';
import ArticleListContainer from '@/components/ArticleListContainer';

import SearchAndFilter from '@/components/SearchAndFilter';
import ArticleSkeleton from '@/components/ArticleSkeleton';
import HeroArticleCard from '@/components/HeroArticleCard';
import HeroSkeleton from '@/components/HeroSkeleton';
import ActiveFilters from '@/components/ActiveFilters';

const { Text, Title } = Typography;

export default function HomePage() {
  const navigate = useNavigate();

  // 博客列表管理 - 使用服务端过滤和分页
  const {
    posts,
    loading,
    error,
    refetch,
    loadMore,
    filter,
    filterBySearch,
    filterByTags,
    filterByStatus,
    clearFilters
  } = useBlogList();

  // 获取热门标签（带计数）
  const { tags: trendingTags } = useBlogDashboard();

  // 适配 SearchAndFilter 的 allTags (只传名称)
  const allTags = useMemo(() => trendingTags.map(t => t.name), [trendingTags]);

  // 处理搜索
  const handleSearch = (query: string) => {
    filterBySearch(query);
  };

  // 处理筛选
  const handleFilter = (newFilters: PostFilter) => {
    if (newFilters.tags !== undefined) {
      filterByTags(newFilters.tags);
    }
    if (newFilters.status) {
      filterByStatus(newFilters.status as unknown as PostStatus);
    }
    // TODO: 支持其他筛选条件
  };



  // 处理文章操作
  const handlePostAction = (action: 'view' | 'edit' | 'share', post: BlogPost) => {
    if (action === 'view') {
      navigate(`/post/${post.slug}`);
    }
    // TODO: implement edit/share
  };

  // 是否正在进行初始加载（没有数据且正在加载）
  const isInitialLoading = loading && posts.length === 0;

  // 格式化当前日期
  const today = new Date().toLocaleDateString('zh-CN', { weekday: 'long', month: 'long', day: 'numeric' });
  const dateParts = today.split(' '); // "X月X日 星期X"

  return (
    <div className="min-h-screen"> 
      {/* Background is handled globally by AppLayout transparent content */}

      <div className="max-w-[1600px] mx-auto py-12 px-6 sm:px-8 lg:px-12">

        {/* APP STORE HEADER */}
        <div className="!mb-5 animate-fade-in-up">
           <div className="flex justify-between items-start mb-0">
           <Text className="block text-gray-500 dark:text-gray-400 font-bold uppercase tracking-wider text-sm mb-0">
             {dateParts[1] || 'Today'}
           </Text>
           <div className="flex items-center gap-4">
              <SearchAndFilter
                onSearch={handleSearch}
                onFilter={handleFilter}
                activeFilters={filter as PostFilter}
                onClearFilters={clearFilters}
                allTags={allTags}
                className="w-96"
              />
              <ActiveFilters 
                  activeFilters={filter as PostFilter}
                  onFilterChange={handleFilter}
                  onClearFilters={clearFilters}
                  className="!mt-0 !mb-0 !justify-end"
              />
           </div>
           </div>
             <div className="flex justify-between items-end">
               <Title level={1} className="!mb-0 !text-5xl font-extrabold tracking-tight" style={{ fontFamily: 'var(--font-display)' }}>
                 {dateParts[0] || '今日阅读'}
               </Title>
             </div>
        </div>

        {/* HERO SECTION */}
        {isInitialLoading ? (
           <HeroSkeleton />
        ) : !error && posts.length > 0 && (
          <div className="mb-12 animate-fade-in-up" style={{ animationDelay: '0.1s' }}>
             <HeroArticleCard post={posts[0]} onNavigate={(slug) => handlePostAction('view', { slug } as BlogPost)} />
          </div>
        )}







        {/* REMAINING POSTS GRID */}
        {isInitialLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[...Array(6)].map((_, index) => (
              <ArticleSkeleton key={index} />
            ))}
          </div>
        ) : error ? (
          <div className="text-center py-16 glassy-card rounded-2xl">
            <Text className="text-red-500">{error.message}</Text>
            <div className="mt-4">
              <Button onClick={() => refetch()}>重新加载</Button>
            </div>
          </div>
        ) : (
          <>
            <div className="animate-fade-in-up" style={{ animationDelay: '0.4s' }}>
                {posts.length > 1 && (
