```javascript
function MyInput({ placeholder, ref }) {
  return <input placeholder={placeholder} ref={ref} />;
}

// 使用时
<MyInput ref={inputRef} />
```

### 2. 文档元数据支持

React 19 原生支持在组件中编写 `<title>`、`<meta>` 和 `<link>`，它们会被自动提升到文档的 `<head>` 中。

```javascript
function BlogPost({ post }) {
  return (
    <article>
      <title>{post.title}</title>
      <meta name="description" content={post.summary} />
      <h1>{post.title}</h1>
    </article>
  );
}
```

### 3. 样式表支持

React 19 会自动管理样式表的加载顺序和优先级。

```javascript
function MyComponent() {
  return (
    <div>
      <link rel="stylesheet" href="style.css" precedence="default" />
      <p>自动处理样式加载</p>
    </div>
  );
}
```



## 自动性能优化：React Compiler

这是 React 19 背后最大的变化。编译器会自动将你的代码转换为记忆化（Memoized）版本。

- **不再需要：** (useMemo)、(useCallback)、(React.memo)。

- **原理：** 编译器会检测数据流，只有当依赖项真正改变时，才会重新计算或渲染相关部分。公式化的理解就是 (UI = Compiler(Component))。



## 过时 API 与 迁移提醒

import { useMemo } from 'react';
import {
  Button,
  Typography,
} from 'antd';
import { useNavigate } from 'react-router-dom';

import { useBlogList, useBlogDashboard } from '@/hooks';
import type { PostFilter, BlogPost } from '@/types';
import { PostStatus } from '@/generated/graphql';
import ArticleListContainer from '@/components/ArticleListContainer';

import SearchAndFilter from '@/components/SearchAndFilter';
import ArticleSkeleton from '@/components/ArticleSkeleton';
import HeroArticleCard from '@/components/HeroArticleCard';
import HeroSkeleton from '@/components/HeroSkeleton';
import ActiveFilters from '@/components/ActiveFilters';

const { Text, Title } = Typography;

export default function HomePage() {
  const navigate = useNavigate();

  // 博客列表管理 - 使用服务端过滤和分页
  const {
    posts,
    loading,
    error,
    refetch,
    loadMore,
    filter,
    filterBySearch,
    filterByTags,
    filterByStatus,
    clearFilters
  } = useBlogList();

  // 获取热门标签（带计数）
  const { tags: trendingTags } = useBlogDashboard();

  // 适配 SearchAndFilter 的 allTags (只传名称)
  const allTags = useMemo(() => trendingTags.map(t => t.name), [trendingTags]);

  // 处理搜索
  const handleSearch = (query: string) => {
    filterBySearch(query);
  };

  // 处理筛选
  const handleFilter = (newFilters: PostFilter) => {
    if (newFilters.tags !== undefined) {
      filterByTags(newFilters.tags);
    }
    if (newFilters.status) {
      filterByStatus(newFilters.status as unknown as PostStatus);
    }
    // TODO: 支持其他筛选条件
  };



  // 处理文章操作
  const handlePostAction = (action: 'view' | 'edit' | 'share', post: BlogPost) => {
    if (action === 'view') {
      navigate(`/post/${post.slug}`);
    }
    // TODO: implement edit/share
  };

  // 是否正在进行初始加载（没有数据且正在加载）
  const isInitialLoading = loading && posts.length === 0;

  // 格式化当前日期
  const today = new Date().toLocaleDateString('zh-CN', { weekday: 'long', month: 'long', day: 'numeric' });
  const dateParts = today.split(' '); // "X月X日 星期X"

  return (
    <div className="min-h-screen"> 
      {/* Background is handled globally by AppLayout transparent content */}

      <div className="max-w-[1600px] mx-auto py-12 px-6 sm:px-8 lg:px-12">

        {/* APP STORE HEADER */}
        <div className="!mb-5 animate-fade-in-up">
           <div className="flex justify-between items-start mb-0">
           <Text className="block text-gray-500 dark:text-gray-400 font-bold uppercase tracking-wider text-sm mb-0">
             {dateParts[1] || 'Today'}
           </Text>
           <div className="flex items-center gap-4">
              <SearchAndFilter
                onSearch={handleSearch}
                onFilter={handleFilter}
                activeFilters={filter as PostFilter}
                onClearFilters={clearFilters}
                allTags={allTags}
                className="w-96"
              />
              <ActiveFilters 
                  activeFilters={filter as PostFilter}
                  onFilterChange={handleFilter}
                  onClearFilters={clearFilters}
                  className="!mt-0 !mb-0 !justify-end"
              />
           </div>
           </div>
             <div className="flex justify-between items-end">
               <Title level={1} className="!mb-0 !text-5xl font-extrabold tracking-tight" style={{ fontFamily: 'var(--font-display)' }}>
                 {dateParts[0] || '今日阅读'}
               </Title>
             </div>
        </div>

        {/* HERO SECTION */}
        {isInitialLoading ? (
           <HeroSkeleton />
        ) : !error && posts.length > 0 && (
          <div className="mb-12 animate-fade-in-up" style={{ animationDelay: '0.1s' }}>
             <HeroArticleCard post={posts[0]} onNavigate={(slug) => handlePostAction('view', { slug } as BlogPost)} />
          </div>
        )}







        {/* REMAINING POSTS GRID */}
        {isInitialLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[...Array(6)].map((_, index) => (
              <ArticleSkeleton key={index} />
            ))}
          </div>
        ) : error ? (
          <div className="text-center py-16 glassy-card rounded-2xl">
            <Text className="text-red-500">{error.message}</Text>
            <div className="mt-4">
              <Button onClick={() => refetch()}>重新加载</Button>
            </div>
          </div>
        ) : (
          <>
            <div className="animate-fade-in-up" style={{ animationDelay: '0.4s' }}>
                {posts.length > 1 && (
                  <div className="flex justify-between items-end mb-6 border-b border-gray-200/50 pb-2 dark:border-gray-700/50">
                    <Title level={3} className="!mb-0 font-bold tracking-tight">
                      更多
                    </Title>
                    <a className="text-blue-500 font-medium text-sm hover:text-blue-600 transition-colors cursor-pointer">
                      查看全部
                    </a>
                  </div>
                )}
                {posts.length > 1 ? (
                  <ArticleListContainer 
                    posts={posts.slice(1)} 
                    loading={false}
                    error={null}
                    onAction={handlePostAction}
                  />
                ) : (
                  <div className="py-10 text-center text-gray-400 italic">
                    {/* Only show this if we have posts (handled by !error && posts.length > 0 check above) but only 1 post */}
                     Stay tuned for more!
                  </div>
                )}
            </div>

            {/* 加载更多按钮 */}
            {posts.length > 1 && (
              <div className="mt-12 text-center pb-12">
                <Button 
                  onClick={() => loadMore()} 
                  loading={loading}
                  disabled={loading}
                  className="px-8 py-6 h-auto rounded-full text-lg font-medium hover:scale-105 transition-transform shadow-lg border-0"
                  style={{
                      background: 'var(--glass-bg)',
                      backdropFilter: 'blur(10px)',
                      color: 'var(--color-primary)'
                  }}
                >
                  {loading ? '加载中...' : '浏览更多往期内容'}
                </Button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

## 🚀 核心新特性

### 1. Actions (异步功能增强)

React 19 引入了对在 HTML 标签中使用异步函数的内置支持，特别是在 `<form>` 中。它可以自动处理待处理状态、错误、乐观更新和顺序提交。

- **用法：** 直接将异步函数传递给 `action` 属性。

```jsx
<form action={async (formData) => {
  const error = await updateName(formData.get("name"));
  if (error) {
    showError(error);
  }
}}>
  <input name="name" />
  <button type="submit">更新</button>
</form>
```

---

## 🎣 新增 Hooks (Actions 相关)

### 1. `useActionState`

用于处理 Action 的状态（原名为 `useFormState`）。

```jsx
// (state, formAction, isPending) = useActionState(actionFn, initialState)
const [error, submitAction, isPending] = useActionState(
  async (previousState, formData) => {
    const error = await updateName(formData.get("name"));
    return error; // 返回的新状态
  },
  null
);
```

### 2. `useFormStatus`

在子组件中获取父级表单的提交状态，无需通过 props 传递。

```jsx
function SubmitButton() {
  const { pending, data, method, action } = useFormStatus();
  return <button disabled={pending}>{pending ? "提交中..." : "提交"}</button>;
}
```

### 3. `useOptimistic`

用于实现“乐观更新”，即在异步请求完成前，先假设成功并更新 UI。

```jsx
const [optimisticName, addOptimisticName] = useOptimistic(
  currentName,
  (state, newName) => newName // 更新逻辑
);
```

